   if let Some(ref status) = filter.status {
       let allowed = ["active", "disabled", "pending"];
       if !allowed.contains(&status.as_str()) {
           // Reject invalid status early
       }
   }
   ```
   This both reduces query complexity and avoids abuse (e.g., huge limits).

3. **Secure error handling, logging, and pooling**
   - Database errors are logged via `tracing` without exposing SQL text to clients, and a properly tuned connection pool is used:
   ```rust
   let rows = match query.fetch_all(&pool).await {
       Ok(r) => r,
       Err(e) => {
           error!(error = %e, "Database error while listing users");
           return Ok(warp::reply::with_status(
