For complex search/filter endpoints, you often need dynamic `WHERE` clauses. The key is to build SQL in a structured way (e.g., using SQLx's `QueryBuilder`) so that **values are always bound as parameters**, while the SQL structure is assembled from trusted code paths.

**PRODUCTION PATTERN**:

```rust
use actix_web::{web, App, Error, HttpResponse, HttpServer, Responder};
use serde::Deserialize;
use sqlx::{postgres::PgPoolOptions, FromRow, PgPool, QueryBuilder};
use std::time::Duration;
use tracing::{error, info, Level};
use tracing_subscriber::FmtSubscriber;

#[derive(Clone)]
struct AppState {
    pool: PgPool,
    env: String,
}

#[derive(Deserialize)]
struct UserFilter {
    username: Option<String>,
    email: Option<String>,
    role: Option<String>,
    limit: Option<i64>,
}

#[derive(FromRow)]
struct User {
    id: i32,
    username: String,
    email: String,
    role: String,
}

async fn search_users(
    filters: web::Query<UserFilter>,
    data: web::Data<AppState>,
) -> Result<impl Responder, Error> {
    let filters = filters.into_inner();

    // LAYER 1: Input validation & normalization
    let max_limit: i64 = 100;
    let limit = filters.limit.unwrap_or(20).clamp(1, max_limit);

    // Basic validation on optional fields
    if let Some(ref u) = filters.username {
        if u.len() > 64 {
            return Ok(HttpResponse::BadRequest().body("username too long"));
        }
    }
    if let Some(ref e) = filters.email {
        if e.len() > 128 {
            return Ok(HttpResponse::BadRequest().body("email too long"));
        }
    }
    if let Some(ref r) = filters.role {
        if r.len() > 32 {
            return Ok(HttpResponse::BadRequest().body("role too long"));
        }
    }

    // LAYER 2: Safe dynamic SQL with QueryBuilder
    let mut qb: QueryBuilder<sqlx::Postgres> = QueryBuilder::new(
        "SELECT id, username, email, role FROM users",
    );

    let mut separated = qb.separated(" AND ");

    if filters.username.is_some() || filters.email.is_some() || filters.role.is_some() {
        qb.push(" WHERE ");

        if let Some(username) = filters.username {
            separated.push("username ILIKE ");
            separated.push_bind(format!("%{}%", username));
        }

        if let Some(email) = filters.email {
            separated.push("email ILIKE ");
            separated.push_bind(format!("%{}%", email));
        }

        if let Some(role) = filters.role {
            separated.push("role = ");
            separated.push_bind(role);
        }
    }

    qb.push(" ORDER BY id ASC ");
    qb.push(" LIMIT ");
    qb.push_bind(limit);

    let query = qb.build_query_as::<User>();

    // LAYER 3: Rate limiting & monitoring could be applied at middleware level (not fully shown)

    let users_res = query.fetch_all(&data.pool).await;

    match users_res {
        Ok(users) => {
            info!("user_search.success"; "count" = users.len() as i64);
            let body = serde_json::to_string(&users).unwrap_or_else(|_| "[]".to_string());
            Ok(HttpResponse::Ok()
                .insert_header(("Content-Type", "application/json"))
                .body(body))
        }
        Err(e) => {
            error!("user_search.error"; "err" = %e);
            Ok(HttpResponse::InternalServerError().body("Internal server error"))
        }
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    // Environment-specific configuration
    let env = std::env::var("APP_ENV").unwrap_or_else(|_| "development".to_string());

    let subscriber = FmtSubscriber::builder()
        .with_max_level(Level::INFO)
        .finish();
    tracing::subscriber::set_global_default(subscriber).expect("setting default subscriber failed");

    let db_url = std::env::var("DATABASE_URL")
        .unwrap_or_else(|_| "postgres://user:pass@localhost/mydb".to_string());

    let pool = PgPoolOptions::new()
        .max_connections(match env.as_str() {
            "production" => 20,
            _ => 5,
        })
        .connect_timeout(Duration::from_secs(5))
        .connect(&db_url)
        .await
        .expect("DB connect failed");

    let state = web::Data::new(AppState { pool, env });

    HttpServer::new(move || {
        App::new()
            .app_data(state.clone())
            // In production, wrap with middlewares for rate limiting, auth, etc.
            .route("/users/search", web::get().to(search_users))
    })
    .bind(("127.0.0.1", 8080))?
    .run()
    .await
}
```

**Defense in Depth Layers**:
1. **Safe query construction with `QueryBuilder`**:
   - Uses `push` only for static SQL fragments controlled by the developer, and `push_bind` for all dynamic values:
   ```rust
   separated.push("email ILIKE ");
   separated.push_bind(format!("%{}%", email));
   ```
   - This ensures SQLx sends user data as parameters, preventing them from changing the query structure.

2. **Input validation and bounding**:
   - Enforces length limits and sane defaults to avoid abuse and reduce risk of DoS:
   ```rust
   let limit = filters.limit.unwrap_or(20).clamp(1, max_limit);
   if let Some(ref u) = filters.username {
       if u.len() > 64 { /* reject */ }
   }
   ```
   - Prevents massive result sets and clearly invalid values.

3. **Secure error handling, monitoring, and environment-aware config**:
   - Logs errors internally with `tracing` without exposing details to clients:
   ```rust
   error!("user_search.error"; "err" = %e);
   Ok(HttpResponse::InternalServerError().body("Internal server error"))
   ```
   - Adjusts pool size and timeouts based on environment; in production you would also add auth, rate limiting, and security headers.

**Additional Protections**:
- **Rate limiting & auth middleware**: Use an Actix middleware or reverse proxy (NGINX, API gateway) to rate-limit endpoints like `/users/search` and require authentication/authorization so attackers can’t brute-force or enumerate freely.
- **Audit logging**: Log high-level search usage (e.g., which authenticated user performed what search, with hashed or summarized filters) to detect abuse patterns without storing full sensitive parameters.
- **Security headers & TLS**: Terminate HTTPS at a secure proxy, set headers like `Strict-Transport-Security`, `Content-Security-Policy`, and `X-Content-Type-Options` either at the proxy or via middleware so queries and responses can’t be intercepted or modified in transit.

With Diesel in Rust you normally get strong SQL injection protection via its query builder, but you can accidentally bypass those protections if you fall back to raw SQL strings or misuse `sql_query`. Here's how that becomes dangerous and how to do it correctly.

**VULNERABLE CODE**:

```rust
use diesel::prelude::*;
use diesel::sql_query;
use diesel::sql_types::{Integer, Text};
use serde::Serialize;

#[derive(QueryableByName, Serialize, Debug)]
struct User {
    #[sql_type = "Integer"]
    id: i32,
    #[sql_type = "Text"]
    username: String,
}

fn find_user_unsafe(conn: &PgConnection, username: &str) -> Result<Vec<User>, diesel::result::Error> {
    // UNSAFE: user input is concatenated directly into SQL string
    let query = format!(
        "SELECT id, username FROM users WHERE username = '{}'",
        username
    );

    // Using raw SQL with user-controlled input
    let results = sql_query(query).load::<User>(conn)?;
    Ok(results)
}

fn main() {
    // Assume `conn` is a valid PgConnection from your pool
    // Example of calling with attacker-controlled input
    // let users = find_user_unsafe(&conn, "admin' OR '1'='1").unwrap();
}
```

**Attack Payload** (if applicable):
```sql
admin' OR '1'='1'--
```

This payload closes the string literal and adds a tautology. The final SQL becomes:

```sql
SELECT id, username FROM users WHERE username = 'admin' OR '1'='1'--'
```

Which returns all users instead of just `admin`.

**Why This Is Dangerous**:
- Direct string interpolation allows an attacker to break out of the intended query structure.
- An attacker can read or modify arbitrary data (e.g., `UNION SELECT` or `DROP TABLE`).
- Raw SQL bypasses Diesel's type-safe query builder and its usual SQL injection protections.

**SECURE VERSION**:

```rust
use diesel::prelude::*;
use diesel::pg::PgConnection;
use diesel::sql_types::{Integer, Text};
use diesel::sql_query;
use serde::Serialize;
use log::{error, info};

// Schema module normally generated by Diesel's CLI (diesel print-schema)
mod schema {
    table! {
        users (id) {
            id -> Int4,
            username -> Varchar,
        }
    }
}

use crate::schema::users::dsl::*;

#[derive(Queryable, Serialize, Debug)]
struct User {
    id: i32,
    username: String,
}

// PRIMARY: safe Diesel query builder (no raw SQL)
fn find_user_safe(conn: &PgConnection, uname: &str) -> Result<Vec<User>, diesel::result::Error> {
    // Basic input validation (defense in depth)
    if uname.trim().is_empty() || uname.len() > 64 {
        return Ok(vec![]); // Fail closed: no results for obviously invalid input
    }

    info!("find_user_safe called for username");

    let result = users
        .filter(username.eq(uname)) // parameterized under the hood
        .limit(10)
        .load::<User>(conn);

    match result {
        Ok(list) => Ok(list),
        Err(e) => {
            // Secure logging: don't log sensitive user input
            error!("Database error in find_user_safe: {}", e);
            Err(e)
        }
    }
}

// If you *must* use raw SQL, use Diesel's bind parameters
#[derive(QueryableByName, Serialize, Debug)]
struct RawUser {
    #[sql_type = "Integer"]
    id: i32,
    #[sql_type = "Text"]
    username: String,
}

fn find_user_safe_raw(conn: &PgConnection, uname: &str) -> Result<Vec<RawUser>, diesel::result::Error> {
    if uname.trim().is_empty() || uname.len() > 64 {
        return Ok(vec![]);
    }

    // `?` placeholders are bound safely, not interpolated
    let query = sql_query("SELECT id, username FROM users WHERE username = $1")
        .bind::<Text, _>(uname);

    let users = query.load::<RawUser>(conn);

    users
}

fn main() {
    // In real code, create a connection pool (r2d2) and obtain a PgConnection
    // Here we just show function signatures and security patterns.
}
```

**Key Security Controls**:
- Query builder with parameters: Using Diesel's DSL (`filter(username.eq(uname))`) ensures user data is passed as parameters, not concatenated into SQL.
- Input validation: Basic length and emptiness checks reduce attack surface and avoid pathological inputs.
- Secure error handling & logging: Log technical errors for operators without echoing raw SQL or user input back to clients, preventing information disclosure.

For dynamic queries in production, you must keep the query *structure* under your control and only let users influence *data*, never raw SQL fragments. With Diesel, that means building queries incrementally with its DSL, and whitelisting any dynamic pieces such as sort columns or directions. You also need production-grade protections like rate limiting, structured logging, and environment-specific configuration.

**PRODUCTION PATTERN**:

```rust
use diesel::prelude::*;
use diesel::pg::PgConnection;
use diesel::r2d2::{self, ConnectionManager};
use log::{error, info, warn};
use std::time::Duration;

mod schema {
    table! {
        users (id) {
            id -> Int4,
            username -> Varchar,
            email -> Varchar,
            created_at -> Timestamptz,
            is_active -> Bool,
        }
    }
}

use crate::schema::users::dsl::*;

type DbPool = r2d2::Pool<ConnectionManager<PgConnection>>;

#[derive(Debug)]
pub enum SortField {
    Username,
    Email,
    CreatedAt,
}

#[derive(Debug)]
pub enum SortDirection {
    Asc,
    Desc,
}

#[derive(Debug, Default)]
pub struct UserFilter<'a> {
    pub username_contains: Option<&'a str>,
    pub email_domain: Option<&'a str>,
    pub active_only: bool,
    pub sort_field: SortField,
    pub sort_direction: SortDirection,
    pub limit: i64,
}

#[derive(Queryable, Debug)]
pub struct User {
    pub id: i32,
    pub username: String,
    pub email: String,
    pub created_at: chrono::NaiveDateTime,
    pub is_active: bool,
}

pub fn search_users(pool: &DbPool, filter: UserFilter) -> Result<Vec<User>, diesel::result::Error> {
    // Rate limiting & monitoring would typically be handled at the HTTP/API layer,
    // but we add logging here to support observability.
    info!("search_users called with filter: {:?}", filter);

    // ENV-specific configuration example (pseudo code)
    let is_prod = std::env::var("APP_ENV").unwrap_or_else(|_| "dev".into()) == "prod";

    // Validate and normalize filter (defense in depth)
    let mut sanitized_filter = filter;
    if sanitized_filter.limit <= 0 || sanitized_filter.limit > 100 {
        sanitized_filter.limit = 50; // enforce sane limits
    }

    // Obtain a DB connection with timeout to avoid resource exhaustion
    let conn = match pool.get_timeout(Duration::from_secs(2)) {
        Ok(c) => c,
        Err(e) => {
            error!("DB connection pool exhausted: {}", e);
            return Err(diesel::result::Error::NotFound); // Fail gracefully
        }
    };

    // Start with base query
    let mut query = users.into_boxed();

    // Apply dynamic filters safely using Diesel DSL
    if let Some(name) = sanitized_filter.username_contains {
        if !name.trim().is_empty() && name.len() <= 64 {
            let pattern = format!("%{}%", name);
            query = query.filter(username.ilike(pattern));
        } else {
            warn!("Rejected suspicious username filter");
        }
    }

    if let Some(domain) = sanitized_filter.email_domain {
        if domain.len() <= 64 && domain.contains('.') {
            let pattern = format!("%@{}", domain);
            query = query.filter(email.ilike(pattern));
        } else {
            warn!("Rejected suspicious email domain filter");
        }
    }

    if sanitized_filter.active_only {
        query = query.filter(is_active.eq(true));
    }

    // Whitelist sort fields and directions
    use diesel::dsl::sql; // Only used with static fragments, not user input

    query = match (&sanitized_filter.sort_field, &sanitized_filter.sort_direction) {
        (SortField::Username, SortDirection::Asc) => query.order(username.asc()),
        (SortField::Username, SortDirection::Desc) => query.order(username.desc()),
        (SortField::Email, SortDirection::Asc) => query.order(email.asc()),
        (SortField::Email, SortDirection::Desc) => query.order(email.desc()),
        (SortField::CreatedAt, SortDirection::Asc) => query.order(created_at.asc()),
        (SortField::CreatedAt, SortDirection::Desc) => query.order(created_at.desc()),
    };

    query = query.limit(sanitized_filter.limit);

    let result = query.load::<User>(&conn);

    if let Err(ref e) = result {
        if is_prod {
            error!("DB error in search_users: {}", e); // technical log only
        } else {
            eprintln!("DEBUG DB error in search_users: {:?}", e);
        }
    }

    result
}

fn init_pool(database_url: &str) -> DbPool {
    let manager = ConnectionManager::<PgConnection>::new(database_url);
    r2d2::Pool::builder()
        .max_size(15)
        .build(manager)
        .expect("Failed to create pool")
}

fn main() {
    // Example initialization; in a real web service this would be in your app setup.
    let database_url = std::env::var("DATABASE_URL").expect("DATABASE_URL must be set");
    let pool = init_pool(&database_url);

    let filter = UserFilter {
        username_contains: Some("alice"),
        email_domain: Some("example.com"),
        active_only: true,
        sort_field: SortField::CreatedAt,
        sort_direction: SortDirection::Desc,
        limit: 20,
    };

    match search_users(&pool, filter) {
        Ok(users) => println!("Found {} users", users.len()),
        Err(e) => println!("Search failed: {}", e),
    }
}
```

**Defense in Depth Layers**:
1. **Safe query construction with Diesel DSL**:
   - The query is built incrementally with Diesel methods like `filter`, `order`, and `limit`, which parameterize user data automatically instead of interpolating into SQL.
   - Example:
   ```rust
   if let Some(name) = sanitized_filter.username_contains {
       let pattern = format!("%{}%", name);
       query = query.filter(username.ilike(pattern));
   }
   ```

2. **Whitelisting dynamic behavior**:
   - User-selectable sort fields and directions are mapped to an enum, so only known-safe column names and directions are possible.
   - Example:
   ```rust
   match (&sanitized_filter.sort_field, &sanitized_filter.sort_direction) {
       (SortField::Email, SortDirection::Desc) => query.order(email.desc()),
       // no chance to inject arbitrary "ORDER BY" text
   }
   ```

3. **Validation, resource control, and secure error handling**:
   - Enforce reasonable `limit` values, filter lengths, and formats; drop obviously malicious or malformed inputs.
   - Use connection pool timeouts to prevent resource exhaustion, and log errors without leaking SQL or user data.
   - Example:
   ```rust
   if sanitized_filter.limit <= 0 || sanitized_filter.limit > 100 {
       sanitized_filter.limit = 50;
   }
   let conn = pool.get_timeout(Duration::from_secs(2))?;
   ```

**Additional Protections**:
- **Environment-specific behavior**: Use an `APP_ENV` or similar variable to control logging verbosity and error messages (less detailed in production to avoid information disclosure).
- **Rate limiting at API layer**: Combine this DB pattern with HTTP-level rate limiting (e.g., per-IP or per-user quotas) to mitigate brute-force and scraping even when queries are safe.
- **Security headers and audit logging**: For a web API, add headers like `Content-Security-Policy`, and log key query events (who searched what, when, and from where) into an audit log with tamper-evident storage for incident response.

Building shell commands with untrusted input is extremely dangerous, especially when those commands interact with databases or backups.

**VULNERABLE CODE**:

```rust
use std::process::Command;
use std::io;

// Simulate getting a database name from an HTTP query parameter or CLI arg
fn get_user_supplied_db_name() -> String {
    // In reality this might come from user input like `std::env::args()` or a web framework
    // For demonstration, pretend the user passed something malicious
    "prod_db; rm -rf /tmp/important".to_string()
}

fn vulnerable_backup() -> io::Result<()> {
    let db_name = get_user_supplied_db_name();

    // VULNERABLE: build a full shell command string with user input
    let cmd = format!("pg_dump {} > /backups/{}.sql", db_name, db_name);

    // Spawns a shell and passes the full string for parsing
    let status = Command::new("sh")
        .arg("-c")
        .arg(&cmd)
        .status()?;

    if !status.success() {
        eprintln!("Backup failed with status: {:?}", status);
    }

    Ok(())
}

fn main() -> io::Result<()> {
    vulnerable_backup()
}
```

**Attack Payload** (if applicable):
```sql
prod_db; rm -rf /tmp/important
```

This payload closes the legitimate `pg_dump` argument and appends a destructive shell command. The resulting command string becomes:

```bash
pg_dump prod_db; rm -rf /tmp/important > /backups/prod_db; rm -rf /tmp/important.sql
```

**Why This Is Dangerous**:
- User input is concatenated directly into a shell command string that is parsed by `/bin/sh`.
- Attackers can inject additional commands using `;`, `&&`, `|`, backticks, or `$()` to run arbitrary programs.
- Running this as a privileged backup service can lead to data destruction, data exfiltration, or full system compromise.

**SECURE VERSION**:

```rust
use std::fs::{self, File};
use std::io::{self, Write};
use std::path::{Path, PathBuf};
use std::process::Command;

// Strict validation: allow only letters, numbers, underscore, and dash
fn validate_db_name(db_name: &str) -> Result<(), String> {
    if db_name.is_empty() || db_name.len() > 64 {
        return Err("Database name has invalid length".to_string());
    }

    if !db_name
        .chars()
        .all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '-')
    {
        return Err("Database name contains invalid characters".to_string());
    }

    Ok(())
}

fn build_backup_path(backup_dir: &Path, db_name: &str) -> io::Result<PathBuf> {
    let mut path = backup_dir.to_path_buf();
    // No user-controlled separators; db_name is validated
    path.push(format!("{}.sql", db_name));
    Ok(path)
}

fn secure_backup(db_name: &str, backup_dir: &Path) -> io::Result<()> {
    // DEFENSE 1: Input validation
    if let Err(e) = validate_db_name(db_name) {
        // Log and fail fast
        eprintln!("[WARN] Rejecting backup request for invalid db name: {} (reason: {})", db_name, e);
        return Err(io::Error::new(io::ErrorKind::InvalidInput, e));
    }

    // DEFENSE 2: No shell, pass args directly to the binary
    let backup_path = build_backup_path(backup_dir, db_name)?;

    // Ensure backup directory exists with safe permissions
    fs::create_dir_all(backup_dir)?;

    // Pre-create the backup file to control permissions explicitly
    let mut file = File::create(&backup_path)?;
    writeln!(file, "-- backup of {}", db_name)?;

    // Call `pg_dump` directly with arguments, no shell parsing
    let status = Command::new("pg_dump")
        .arg("--format=plain")
        .arg("--no-owner")
        .arg("--dbname")
        .arg(db_name) // Safe: passed as a single argument
        .arg("--file")
        .arg(&backup_path)
        .status()?;

    if !status.success() {
        // DEFENSE 3: Fail securely, do not expose command details to callers
        eprintln!(
            "[ERROR] pg_dump failed for db '{}' with status: {:?}",
            db_name, status
        );
        return Err(io::Error::new(
            io::ErrorKind::Other,
            "backup command failed",
        ));
    }

    println!("[INFO] Backup completed for '{}' at {:?}", db_name, backup_path);

    Ok(())
}

fn main() -> io::Result<()> {
    // Example: this would usually come from a safe configuration or sanitized request
    let db_name = "prod_db_1";
    let backup_dir = Path::new("/var/backups/databases");

    secure_backup(db_name, backup_dir)
}
```

**Key Security Controls**:
- **No shell invocation**: Uses `Command::new("pg_dump")` with explicit `.arg()` calls instead of `sh -c`, so the OS never re-parses a combined string as a shell command.
- **Strict input validation**: `validate_db_name` enforces an allowlist of characters and length, preventing shell metacharacters, spaces, and path traversal from ever reaching the command.
- **Secure error handling and logging**: Logs failures with minimal detail, fails fast on invalid input, and avoids echoing full command lines or sensitive paths back to users.

In production, you should treat **every user-controlled option as untrusted** and map it into a **fixed set of safe arguments**. Never pass raw strings to a shell; always use structured arguments and strict validation.

**PRODUCTION PATTERN**:

```rust
use std::fs;
use std::io;
use std::path::{Path, PathBuf};
use std::process::{Command, Stdio};
use chrono::Utc;

#[derive(Debug, Clone, Copy)]
enum BackupMode {
    Full,
    SchemaOnly,
}

#[derive(Debug)]
struct BackupRequest {
    db_name: String,
    mode: BackupMode,
    compression: bool,
    // Only allow selecting from a small set of logical directories
    target_profile: String,
    requester_ip: String,
}

fn validate_db_name(db_name: &str) -> Result<(), String> {
    if db_name.is_empty() || db_name.len() > 64 {
        return Err("Database name has invalid length".into());
    }
    if !db_name
        .chars()
        .all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '-')
    {
        return Err("Database name contains invalid characters".into());
    }
    Ok(())
}

fn resolve_backup_dir(profile: &str, env: &str) -> Result<PathBuf, String> {
    // Map a limited set of user profiles to actual paths
    let base = match env {
        "prod" => "/var/backups/prod", // from config in real code
        "staging" => "/var/backups/staging",
        _ => return Err("Unknown environment".into()),
    };

    let subdir = match profile {
        "daily" => "daily",
        "weekly" => "weekly",
        _ => return Err("Unknown backup profile".into()),
    };

    Ok(Path::new(base).join(subdir))
}

fn build_backup_command(req: &BackupRequest, env: &str) -> Result<(Command, PathBuf), String> {
    validate_db_name(&req.db_name)?;

    let backup_dir = resolve_backup_dir(&req.target_profile, env)?;
    fs::create_dir_all(&backup_dir).map_err(|e| format!("Create dir failed: {e}"))?;

    let timestamp = Utc::now().format("%Y%m%dT%H%M%SZ");
    let mut file_name = format!("{}_{}.sql", req.db_name, timestamp);

    if req.compression {
        file_name.push_str(".gz");
    }

    let backup_path = backup_dir.join(file_name);

    // PRIMARY DEFENSE: structured arguments, no shell
    let mut cmd = Command::new("pg_dump");
    cmd.arg("--dbname").arg(&req.db_name);

    match req.mode {
        BackupMode::Full => { /* default */ }
        BackupMode::SchemaOnly => {
            cmd.arg("--schema-only");
        }
    }

    if req.compression {
        // Use a pipeline by spawning `pg_dump` and piping to `gzip` via Rust,
        // not via `sh -c`.
        cmd.arg("--format=plain");
        cmd.stdout(Stdio::piped());
    } else {
        cmd.arg("--file").arg(&backup_path);
    }

    Ok((cmd, backup_path))
}

fn execute_backup(req: &BackupRequest, env: &str) -> io::Result<()> {
    // AUDIT LOG: who requested what
    println!(
        "[AUDIT] Backup requested: db='{}', mode={:?}, compression={}, profile='{}', ip={}",
        req.db_name, req.mode, req.compression, req.target_profile, req.requester_ip
    );

    let (mut cmd, backup_path) = match build_backup_command(req, env) {
        Ok(v) => v,
        Err(e) => {
