    let start = std::time::Instant::now();
    if let Err(e) = execute_search(&mut client, filters) {
        eprintln!("[ERROR] search query failed: {}", e);
        // HTTP 500 in real app
    }
    let elapsed = start.elapsed();
    if env == "production" && elapsed > Duration::from_millis(200) {
        eprintln!(
            "[ALERT] Slow query detected: {:?} (>200ms threshold)", 
            elapsed
        );
        // send metric/alert to monitoring system
    }

    // SECURITY HEADERS (conceptual; in a real HTTP handler you'd set them on the response)
    println!("[DEBUG] Would set headers: X-Content-Type-Options=nosniff, X-Frame-Options=DENY, Content-Security-Policy=default-src 'none'");

    Ok(())
}
```

**Defense in Depth Layers**:
1. **Type-safe, parameterized dynamic SQL**: `build_search_query` uses numbered placeholders (`$1`, `$2`, ...) and collects parameters in a separate vector, so user input is never concatenated directly into the query text.
2. **Strict input validation and normalization**: `validate_filters` enforces length limits, character whitelists, and pagination bounds, reducing the attack surface and preventing abuse such as huge `LIMIT` values.
3. **Audit logging and performance monitoring**: Structured logs of filters and query templates, plus simple latency checks, make it easier to detect suspicious patterns, brute-force attempts, and slow queries that might indicate abuse.

**Additional Protections**:
- Environment-specific behavior (via `APP_ENV`): in production, you would disable verbose debug logs, enable stricter timeouts, and integrate with centralized logging/metrics systems.
- Rate limiting by client IP and endpoint to reduce brute-force and automated probing; in Rust you can use a middleware or shared token-bucket implementation in the web framework.
- Secure HTTP response handling: in a real web server, set security headers (CSP, X-Frame-Options, X-Content-Type-Options) and return generic error messages while logging detailed internal errors server-side.

When using SQLx in Rust, SQL injection becomes a risk if you build SQL strings by concatenating user input instead of using parameters. This pattern looks similar to what caused major incidents like the MOVEit Transfer SQL injection (CVE-2023-34362).

**VULNERABLE CODE**:

```rust
use actix_web::{web, App, HttpRequest, HttpResponse, HttpServer, Responder};
use sqlx::{postgres::PgPoolOptions, PgPool};

#[derive(Clone)]
struct AppState {
    db: PgPool,
}

async fn get_user(req: HttpRequest, data: web::Data<AppState>) -> impl Responder {
    let query_param = req
        .match_info()
        .get("username")
        .unwrap_or("")
        .to_string();

    // VULNERABLE: direct string concatenation with user input
    let raw_sql = format!(
        "SELECT id, username, email FROM users WHERE username = '{}'",
        query_param
    );

    // Any error is leaked back to the client
    let row = match sqlx::query(&raw_sql).fetch_one(&data.db).await {
        Ok(r) => r,
        Err(e) => {
            return HttpResponse::InternalServerError()
                .body(format!("DB error: {}", e));
        }
    };

    let username: String = row.get("username");
    let email: String = row.get("email");

    HttpResponse::Ok().body(format!("User: {} <{}>", username, email))
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let db = PgPoolOptions::new()
        .max_connections(5)
        .connect("postgres://user:pass@localhost/app")
        .await
        .expect("DB connect failed");

    let state = AppState { db };

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(state.clone()))
            .route("/user/{username}", web::get().to(get_user))
    })
    .bind(("127.0.0.1", 8080))?
    .run()
    .await
}
```

**Attack Payload** (if applicable):
```sql
' UNION SELECT id, password, email FROM admin_users--
```

If the attacker calls:

```text
GET /user/' UNION SELECT id, password, email FROM admin_users--
```

the resulting SQL becomes:

```sql
SELECT id, username, email FROM users WHERE username = '' UNION SELECT id, password, email FROM admin_users--'
```

This leaks data from the `admin_users` table.

**Why This Is Dangerous**:
- User input is directly embedded into the SQL string, allowing attackers to change the query structure.
- There is no input validation or allowed-character enforcement, so arbitrary SQL can be injected.
- Detailed database errors are returned to the client, leaking internal information useful for exploitation.

**SECURE VERSION**:

```rust
use actix_web::{web, App, HttpRequest, HttpResponse, HttpServer, Responder};
use sqlx::{postgres::PgPoolOptions, PgPool, Row};
use regex::Regex;
use std::sync::Arc;

#[derive(Clone)]
struct AppState {
    db: PgPool,
}

fn validate_username(username: &str) -> Result<(), &'static str> {
    // DEFENSE-IN-DEPTH: enforce a simple, safe pattern
    // only allow 3-32 alphanumeric and underscore characters
    let re = Regex::new(r"^[A-Za-z0-9_]{3,32}$").unwrap();
    if re.is_match(username) {
        Ok(())
    } else {
        Err("invalid username format")
    }
}

async fn get_user(req: HttpRequest, data: web::Data<Arc<AppState>>) -> impl Responder {
    let username = match req.match_info().get("username") {
        Some(u) => u,
        None => {
            return HttpResponse::BadRequest().body("missing username");
        }
    };

    if let Err(_) = validate_username(username) {
        // Do not echo unsafe input back to the client
        return HttpResponse::BadRequest().body("invalid username");
    }

    // PRIMARY DEFENSE: parameterized query with SQLx
    let result = sqlx::query("SELECT id, username, email FROM users WHERE username = $1")
        .bind(username)
        .fetch_one(&data.db)
        .await;

    match result {
        Ok(row) => {
            let username: String = row.get("username");
            let email: String = row.get("email");
            HttpResponse::Ok().body(format!("User: {} <{}>", username, email))
        }
        Err(sqlx::Error::RowNotFound) => {
            HttpResponse::NotFound().body("user not found")
        }
        Err(e) => {
            // SECURE ERROR HANDLING: log internally, generic error to client
            eprintln!("[ERROR] DB query failed: {}", e);
            HttpResponse::InternalServerError().body("internal server error")
        }
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let db = PgPoolOptions::new()
        .max_connections(5)
        .connect("postgres://user:pass@localhost/app")
        .await
        .expect("DB connect failed");

    let state = Arc::new(AppState { db });

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(state.clone()))
            .route("/user/{username}", web::get().to(get_user))
    })
    .bind(("127.0.0.1", 8080))?
    .run()
    .await
}
```

**Key Security Controls**:
- Parameterized queries with SQLx: `bind(username)` ensures user input is treated strictly as data, not executable SQL, preventing injection even with malicious strings.
- Input validation with a strict regex: limits usernames to a safe character set and length, reducing attack surface and accidental misuse.
- Secure error handling and logging: internal errors are logged server-side while clients receive generic messages, preventing leakage of database schema or configuration details.

For production APIs that need dynamic WHERE clauses and pagination, you should still avoid string concatenation of raw user input. With SQLx, you can either:

1. Use `QueryBuilder` to build parameterized queries dynamically, or
2. Restrict dynamic parts to a small, validated set of options (e.g., sort fields, allowed filters).

Below is a production-style pattern using `QueryBuilder`, structured logging, and some defense-in-depth controls.

**PRODUCTION PATTERN**:

```rust
use actix_web::{web, App, HttpRequest, HttpResponse, HttpServer, Responder};
use serde::Deserialize;
use sqlx::{postgres::PgPoolOptions, PgPool, Row, QueryBuilder};
use std::sync::Arc;
use env_logger;
use log::{error, info, warn};

#[derive(Clone)]
struct AppState {
    db: PgPool,
    env: String,
}

#[derive(Deserialize, Debug)]
struct UserFilter {
    username: Option<String>,
    email: Option<String>,
    role: Option<String>,
    page: Option<u32>,
    per_page: Option<u32>,
    sort_by: Option<String>,  // e.g. "username" or "created_at"
    sort_dir: Option<String>, // "asc" or "desc"
}

fn validate_sort(sort_by: &str, sort_dir: &str) -> Option<( &'static str, &'static str )> {
    // Whitelist allowed columns and directions
    let col = match sort_by {
        "username" => "username",
        "created_at" => "created_at",
        _ => return None,
    };

    let dir = match sort_dir.to_lowercase().as_str() {
        "asc" => "ASC",
        "desc" => "DESC",
        _ => return None,
    };

    Some((col, dir))
}

async fn list_users(
    req: HttpRequest,
    query: web::Query<UserFilter>,
    data: web::Data<Arc<AppState>>,
) -> impl Responder {
    let client_ip = req.peer_addr().map(|a| a.ip().to_string()).unwrap_or("unknown".into());
    info!("/users list requested from {} with filters: {:?}", client_ip, &*query);

    // RATE LIMITING (conceptual): in real code integrate tower/redis-based limiter
    // Here we just log repeated access signs.

    let page = query.page.unwrap_or(1).max(1);
    let per_page = query.per_page.unwrap_or(20).clamp(1, 100);
    let offset = (page - 1) * per_page;

    // Base query
    let mut qb: QueryBuilder<'_, sqlx::Postgres> = QueryBuilder::new(
        "SELECT id, username, email, role, created_at FROM users WHERE 1=1",
    );

    // Dynamic filters with PARAMETER BINDING ONLY
    if let Some(ref username) = query.username {
        qb.push(" AND username ILIKE ")
            .push_bind(format!("%{}%", username));
    }

    if let Some(ref email) = query.email {
        qb.push(" AND email ILIKE ")
            .push_bind(format!("%{}%", email));
    }

    if let Some(ref role) = query.role {
        qb.push(" AND role = ")
            .push_bind(role);
    }

    // Safe sorting: only allow whitelisted columns and directions
    if let (Some(sort_by), Some(sort_dir)) = (&query.sort_by, &query.sort_dir) {
        if let Some((col, dir)) = validate_sort(sort_by, sort_dir) {
            qb.push(" ORDER BY ").push(col).push(" ").push(dir);
        } else {
            warn!("Invalid sort parameters from {}: {}, {}", client_ip, sort_by, sort_dir);
        }
    } else {
        qb.push(" ORDER BY created_at DESC");
    }

    qb.push(" LIMIT ").push_bind(per_page as i64);
    qb.push(" OFFSET ").push_bind(offset as i64);

    let query_built = qb.build();

    let rows_res = query_built.fetch_all(&data.db).await;

    match rows_res {
        Ok(rows) => {
            // Basic JSON array response
            let mut users = Vec::new();
            for row in rows {
                users.push(serde_json::json!({
                    "id": row.get::<i64, _>("id"),
                    "username": row.get::<String, _>("username"),
                    "email": row.get::<String, _>("email"),
                    "role": row.get::<String, _>("role"),
                }));
            }

            // SECURITY HEADERS
            HttpResponse::Ok()
                .append_header(("Content-Type", "application/json"))
                .append_header(("X-Content-Type-Options", "nosniff"))
                .append_header(("X-Frame-Options", "DENY"))
                .body(serde_json::to_string(&users).unwrap())
        }
        Err(e) => {
            error!("DB error listing users from {}: {}", client_ip, e);
            // Graceful degradation: return 503 in case of DB outage in prod
            if data.env == "production" {
                HttpResponse::ServiceUnavailable().body("service temporarily unavailable")
            } else {
                HttpResponse::InternalServerError().body("database error")
            }
        }
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    env_logger::init();

    let env = std::env::var("APP_ENV").unwrap_or_else(|_| "development".into());

    let database_url = std::env::var("DATABASE_URL")
        .expect("DATABASE_URL must be set");

    let max_conns = if env == "production" { 20 } else { 5 };

    let db = PgPoolOptions::new()
        .max_connections(max_conns)
        .connect(&database_url)
        .await
        .expect("DB connect failed");

    let state = Arc::new(AppState { db, env });

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(state.clone()))
            .route("/users", web::get().to(list_users))
    })
    .bind(("0.0.0.0", 8080))?
    .run()
    .await
}
```

**Defense in Depth Layers**:
1. **Parameterized dynamic query construction**:
   - Uses `QueryBuilder` with `.push_bind(...)` for all user-controlled values:
   ```rust
   if let Some(ref email) = query.email {
       qb.push(" AND email ILIKE ").push_bind(format!("%{}%", email));
   }
   ```
   This ensures SQLx sends parameters separately from the query text, preventing injection.

2. **Whitelisting for non-parameterizable parts (like ORDER BY)**:
   - Column names and sort directions cannot be bound as parameters in SQL, so they are limited to a known-safe set:
   ```rust
   if let Some((col, dir)) = validate_sort(sort_by, sort_dir) {
       qb.push(" ORDER BY ").push(col).push(" ").push(dir);
   }
   ```
   Only allowed identifiers are ever interpolated into the query string.

3. **Environment-aware error handling and monitoring**:
   - Uses `log` + `env_logger` for structured server-side logging of errors and suspicious input patterns.
   - Returns generic errors to clients, with more cautious behavior in production:
   ```rust
   if data.env == "production" {
       HttpResponse::ServiceUnavailable().body("service temporarily unavailable")
   } else {
       HttpResponse::InternalServerError().body("database error")
   }
   ```
   This both prevents information leakage and supports monitoring/alerting on backend logs.

**Additional Protections**:
- **Environment-specific configuration**: Connection pool size and error responses depend on `APP_ENV`, letting you harden production differently from development.
- **Audit-friendly logging**: Logs client IPs and filter parameters for `/users` requests, which helps detect abuse or brute-force-style enumeration.
- **Security headers and graceful degradation**: Adds basic security headers (`X-Content-Type-Options`, `X-Frame-Options`) and returns 503 during DB issues in production, maintaining a safer user experience while protecting implementation details.
